module counter_3bit_updown(reset, RESET, UP_DOWN, COUNT);
input reset, RESET, UP_DOWN;
output reg [2:0] COUNT;

always @(posedge reset or posedge RESET) begin
    if (RESET)
        COUNT <= 3'b000;
    else if (UP_DOWN)
        COUNT <= COUNT + 1;
    else
        COUNT <= COUNT - 1;
end

endmodule
